import graph3;
        size(7cm);
        currentprojection=orthographic(5,4,3);
        real A=1.1,B=1.1,C=1.7;
        surface s=surface(new triple(pair t){real th=t.x, ph=t.y; return (A*sin(ph)*cos(th), B*sin(ph)*sin(th), C*cos(ph));},(0,0),(2pi,pi),32,16);
        draw(s, rgb(0.95,0.70,0.30)+opacity(0.85), meshpen=rgb(0.55,0.35,0.05)+linewidth(0.2pt));
        draw((-2.0,0,0)--(2.0,0,0),gray,Arrow3); draw((0,-2.0,0)--(0,2.0,0),gray,Arrow3); draw((0,0,-2.0)--(0,0,2.0),gray,Arrow3);
        label("$x$",(2.0,0,0),S); label("$y$",(0,2.0,0),E); label("$z$",(0,0,2.0),N);

