        surface s=surface(new triple(pair t){real u=t.x, v=t.y; return (cosh(v)*cos(u), cosh(v)*sin(u), sinh(v));},(0,-1.1),(2pi,1.1),32,14);
        draw(s, rgb(0.40,0.75,0.55)+opacity(0.85), meshpen=rgb(0.10,0.40,0.25)+linewidth(0.2pt));
