        surface s=surface(new triple(pair t){real u=t.x, v=t.y; return (sinh(v)*cos(u), sinh(v)*sin(u), cosh(v));},(0,0),(2pi,1.15),28,10);
        draw(s, rgb(0.85,0.45,0.55)+opacity(0.85), meshpen=rgb(0.45,0.15,0.20)+linewidth(0.2pt));
        surface s2=surface(new triple(pair t){real u=t.x, v=t.y; return (sinh(v)*cos(u), sinh(v)*sin(u), -cosh(v));},(0,0),(2pi,1.15),28,10);
        draw(s2, rgb(0.85,0.45,0.55)+opacity(0.85), meshpen=rgb(0.45,0.15,0.20)+linewidth(0.2pt));
        draw((-2.0,0,0)--(2.0,0,0),gray,Arrow3); draw((0,-2.0,0)--(0,2.0,0),gray,Arrow3); draw((0,0,-2.0)--(0,0,2.0),gray,Arrow3);
        label("$x$",(2.0,0,0),S); label("$y$",(0,2.0,0),E); label("$z$",(0,0,2.0),N);

