import graph3;
        size(7cm);
        currentprojection=orthographic(5,4,3);
        surface s=surface(new triple(pair t){return (t.x, t.y, t.x*t.x - t.y*t.y);},(-1.2,-1.2),(1.2,1.2),24,24);
        draw(s, rgb(0.55,0.60,0.85)+opacity(0.85), meshpen=rgb(0.20,0.25,0.50)+linewidth(0.2pt));
